PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?ingredientLabel ?cuisineLabel
WHERE {
  {
    wd:Q826059 wdt:P868 ?food .
    ?food rdfs:label ?ingredientLabel .
    FILTER(langMatches(lang(?ingredientLabel), "en"))
    BIND("Vietnamese cuisine" AS ?cuisineLabel)
  }
  UNION
  {
    wd:Q841984 wdt:P868 ?food .
    ?food rdfs:label ?ingredientLabel .
    FILTER(langMatches(lang(?ingredientLabel), "en"))
    BIND("Thai cuisine" AS ?cuisineLabel)
  }
  UNION
  {
    wd:Q691365 wdt:P868 ?food .
    ?food rdfs:label ?ingredientLabel .
    FILTER(langMatches(lang(?ingredientLabel), "en"))
    BIND("Sichuan cuisine" AS ?cuisineLabel)
  }
} ORDER BY ?cuisineLabel ?ingredientLabel

